// Calls: calendarService.scheduleOrder(orderId, product, desiredDate, workHoursDelta)
// Returns: { ready_date, shipping_date, event }
// Validates daily capacity is not exceeded
const { scheduleOrder } = require('./app/js/calendar/calendarService.js');
const { getOrder } = require('./app/js/orders/orderService.js');
const { getProductByName } = require('./app/js/orders/productService.js');
const { orderId } = $input.first().json;
const order = getOrder(orderId);
const product = getProductByName(order.product_name);
const scheduled = scheduleOrder(orderId, product, order.desired_date, 0);
return [{ json: { orderId, scheduled, hasSlot: !!scheduled } }];

const { updateRow } = require('./app/js/data/rowRepository.js');
const { nowIso } = require('./app/js/utils/time.js');
const { updateOrderStatus } = require('./app/js/orders/orderService.js');
const { scheduled, orderId } = $input.first().json;
updateRow('Orders', 'order_id', orderId, {
  ready_date: scheduled.ready_date,
  shipping_date: scheduled.shipping_date,
  updated_at: nowIso()
});
updateOrderStatus(orderId, 'Scheduled');
return $input.all();

const { createTask } = require('./app/js/tasks/taskService.js');
const { sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const { orderId, scheduled } = $input.first().json;
const task = createTask({ orderId, type: 'Production', title: 'Почати виробництво', priority: 'INFO', dueAt: scheduled.event.start_at });
await sendManagerAlert(`📅 Замовлення ${orderId} заплановано на ${scheduled.ready_date}`);
return [{ json: { task } }];

const { sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const { orderId } = $input.first().json;
await sendManagerAlert(`⚠️ Немає вільного слоту для ${orderId}. Потрібне ручне планування.`);
return $input.all();
